from __future__ import annotations

import os
import time
import secrets
from dataclasses import dataclass
from typing import Dict, Optional

from flask import Flask, jsonify, request
from eth_account.messages import encode_defunct
from web3 import Web3


app = Flask(__name__)
w3 = Web3()

NONCE_TTL_SECONDS = int(os.getenv("NONCE_TTL_SECONDS", "300"))
TOKEN_TTL_SECONDS = int(os.getenv("TOKEN_TTL_SECONDS", "3600"))
APP_DOMAIN = os.getenv("APP_DOMAIN", "example.com")
APP_NAME = os.getenv("APP_NAME", "Web3 Auth Service")


@dataclass
class NonceRecord:
    nonce: str
    issued_at: int
    expires_at: int
    consumed: bool = False


@dataclass
class SessionRecord:
    address: str
    issued_at: int
    expires_at: int


nonces: Dict[str, NonceRecord] = {}
sessions: Dict[str, SessionRecord] = {}


def now_ts() -> int:
    return int(time.time())


def cleanup() -> None:
    current = now_ts()
    expired_nonce_keys = [k for k, v in nonces.items() if v.expires_at <= current]
    for k in expired_nonce_keys:
        nonces.pop(k, None)

    expired_session_keys = [k for k, v in sessions.items() if v.expires_at <= current]
    for k in expired_session_keys:
        sessions.pop(k, None)


def normalize_address(address: str) -> str:
    return Web3.to_checksum_address(address)


def build_message(address: str, nonce: str) -> str:
    return (
        f"{APP_NAME} wants you to sign in with your Ethereum account:\n"
        f"{address}\n\n"
        f"Sign this message to authenticate.\n\n"
        f"Domain: {APP_DOMAIN}\n"
        f"Nonce: {nonce}\n"
        f"Issued At: {now_ts()}"
    )


def issue_nonce(address: str) -> NonceRecord:
    cleanup()
    checksum_address = normalize_address(address)
    nonce = secrets.token_urlsafe(24)
    issued = now_ts()
    record = NonceRecord(
        nonce=nonce,
        issued_at=issued,
        expires_at=issued + NONCE_TTL_SECONDS,
        consumed=False,
    )
    nonces[checksum_address] = record
    return record


def verify_signature(address: str, message: str, signature: str) -> bool:
    try:
        checksum_address = normalize_address(address)
        encoded_message = encode_defunct(text=message)
        recovered = w3.eth.account.recover_message(encoded_message, signature=signature)
        recovered_checksum = normalize_address(recovered)
        return recovered_checksum == checksum_address
    except Exception:
        return False


def create_session(address: str) -> str:
    token = secrets.token_urlsafe(32)
    issued = now_ts()
    sessions[token] = SessionRecord(
        address=normalize_address(address),
        issued_at=issued,
        expires_at=issued + TOKEN_TTL_SECONDS,
    )
    return token


def extract_bearer_token() -> Optional[str]:
    auth_header = request.headers.get("Authorization", "")
    if not auth_header.startswith("Bearer "):
        return None
    return auth_header.split(" ", 1)[1].strip() or None


@app.route("/health", methods=["GET"])
def health():
    return jsonify({"status": "ok"}), 200


@app.route("/auth/nonce", methods=["POST"])
def auth_nonce():
    cleanup()
    data = request.get_json(silent=True) or {}
    address = data.get("address")

    if not address:
        return jsonify({"error": "address is required"}), 400

    try:
        checksum_address = normalize_address(address)
    except Exception:
        return jsonify({"error": "invalid ethereum address"}), 400

    record = issue_nonce(checksum_address)
    message = build_message(checksum_address, record.nonce)

    return jsonify(
        {
            "address": checksum_address,
            "nonce": record.nonce,
            "message": message,
            "expires_at": record.expires_at,
        }
    ), 200


@app.route("/auth/verify", methods=["POST"])
def auth_verify():
    cleanup()
    data = request.get_json(silent=True) or {}
    address = data.get("address")
    signature = data.get("signature")
    message = data.get("message")

    if not address or not signature or not message:
        return jsonify({"error": "address, message, and signature are required"}), 400

    try:
        checksum_address = normalize_address(address)
    except Exception:
        return jsonify({"error": "invalid ethereum address"}), 400

    record = nonces.get(checksum_address)
    if not record:
        return jsonify({"error": "no nonce issued for address"}), 400

    if record.consumed:
        return jsonify({"error": "nonce already used"}), 400

    if record.expires_at <= now_ts():
        nonces.pop(checksum_address, None)
        return jsonify({"error": "nonce expired"}), 400

    expected_message = build_message(checksum_address, record.nonce)
    if message != expected_message:
        return jsonify({"error": "message does not match expected payload"}), 400

    if not verify_signature(checksum_address, message, signature):
        return jsonify({"error": "invalid signature"}), 401

    record.consumed = True
    token = create_session(checksum_address)

    return jsonify(
        {
            "authenticated": True,
            "address": checksum_address,
            "token": token,
            "expires_at": sessions[token].expires_at,
        }
    ), 200


@app.route("/auth/me", methods=["GET"])
def auth_me():
    cleanup()
    token = extract_bearer_token()
    if not token:
        return jsonify({"error": "missing bearer token"}), 401

    session = sessions.get(token)
    if not session:
        return jsonify({"error": "invalid or expired token"}), 401

    return jsonify(
        {
            "authenticated": True,
            "address": session.address,
            "issued_at": session.issued_at,
            "expires_at": session.expires_at,
        }
    ), 200


@app.route("/auth/logout", methods=["POST"])
def auth_logout():
    cleanup()
    token = extract_bearer_token()
    if not token:
        return jsonify({"error": "missing bearer token"}), 401

    if token in sessions:
        sessions.pop(token, None)

    return jsonify({"logged_out": True}), 200


